patch:
--- a/comparator_64bit.v
+++ b/comparator_64bit.v
@@ -1,15 +1,15 @@
 module comparator_64bit(
   input [63:0] data_x,
   input [63:0] data_y,
   output reg eq,
   output reg lt,
   output reg gt
 );

-  always @(data_x) begin
+  always @(data_x or data_y) begin
     if(data_x == data_y) begin
       eq = 1'b1;
       lt = 1'b0;
       gt = 1'b0;
     end else if(data_x < data_y) begin
       eq = 1'b0;
       lt = 1'b1;

before_code:
module comparator_64bit(
  input [63:0] data_x,
  input [63:0] data_y,
  output reg eq,
  output reg lt,
  output reg gt
);

  always @(data_x) begin
    if(data_x == data_y) begin
      eq = 1'b1;
      lt = 1'b0;
      gt = 1'b0;
    end else if(data_x < data_y) begin
      eq = 1'b0;
      lt = 1'b1;
      gt = 1'b0;
    end else begin
      eq = 1'b0;
      lt = 1'b0;
      gt = 1'b1;
    end
  end

endmodule

after_code:
module comparator_64bit(
  input [63:0] data_x,
  input [63:0] data_y,
  output reg eq,
  output reg lt,
  output reg gt
);

  always @(data_x or data_y) begin
    if(data_x == data_y) begin
      eq = 1'b1;
      lt = 1'b0;
      gt = 1'b0;
    end else if(data_x < data_y) begin
      eq = 1'b0;
      lt = 1'b1;
      gt = 1'b0;
    end else begin
      eq = 1'b0;
      lt = 1'b0;
      gt = 1'b1;
    end
  end

endmodule
